import { Box, Card, CardContent, CircularProgress, FormControlLabel, Radio, Typography } from "@mui/material";
import React from "react";

interface ShippingCardProps {
    isLoadingCep: boolean;
    bgColor?: string;
}

const ShippingCard: React.FC<ShippingCardProps> = ({ isLoadingCep, bgColor = "white" }) => {

    return (
        <Card sx={{ bgcolor: bgColor }} elevation={3}>
            <CardContent>
                <Typography gutterBottom>
                    Preço e prazos
                </Typography>
                {isLoadingCep ?
                    <CircularProgress color="primary" />
                    :
                    <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <Typography color="text.secondary">
                            Entrega em até 10 dias úteis
                        </Typography>
                        <FormControlLabel
                            value="start"
                            control={<Radio />}
                            checked={true}
                            label="R$ 5,00"
                            labelPlacement="start"
                        />
                    </Box>
                }
            </CardContent>
        </Card>
    );
};

export default ShippingCard;